mapper.insert:
INSERT INTO CTRT_MGR ( CTRT_MGR_NO , USER_NO , MGR_ASGN_DT , CHG_YN , RENT_CTRT_NO ) SELECT SEQ_CTRT_MGR.nextval, T.* FROM (
SELECT #{manager} AS USER_NO , sysdate AS MGR_ASGN_DT , 'N' AS CHG_YN , #{map.rentCtrtNo} AS RENT_CTRT_NO FROM DUAL
) T

INSERT INTO HSHLD_HEAD (
    USER_NO, HO_NO, INOUT_CD
) VALUES (
    #{USER_NO},#{HO_NO},'WAIT'
)

mapper.select:
SELECT USER_NO
FROM APLCT
WHERE APLCT_NO = #{aplctNo}

SELECT * FROM ( SELECT B.*, ROWNUM AS RNUM FROM ( SELECT /* kr.or.ddit.domain.central.rentCtrt.mapper.IRentCtrtMapper.selectContracts */ C.RENT_CTRT_NO, U.USER_ID, C.USER_NO, U.USER_NM, A.APT_CMPLEX_NO, A.APT_CMPLEX_NM, C.CTRT_APRV_DT, C.MVIN_DT, C.MVOUT_DT, L.RENT_TYPE_CD, C.DPST_AMT, C.MTHLY_RENT_AMT, C.CTRT_STTS_CD, M.USER_NO AS CTRT_MGR_USER_NO, U2.USER_ID AS CTRT_MGR_USER_ID, U2.USER_NM AS CTRT_MGR_USER_NM FROM RENT_CTRT C INNER JOIN CTRT_MGR M ON C.RENT_CTRT_NO = M.RENT_CTRT_NO INNER JOIN RENT_LISTING L ON C.RENT_LSTG_NO = L.RENT_LSTG_NO INNER JOIN APT_DETAIL H ON H.HO_NO = L.HO_NO INNER JOIN APT_UNIT D ON D.DONG_NO = H.DONG_NO INNER JOIN APT_COMPLEX A ON A.APT_CMPLEX_NO = D.APT_CMPLEX_NO LEFT OUTER JOIN MEMBER U ON C.USER_NO = U.USER_NO LEFT OUTER JOIN MEMBER U2 ON M.USER_NO = U2.USER_NO
M.CHG_YN = 'N' AND M.USER_NO = #{userNo} AND C.RENT_CTRT_NO LIKE '%' || #{ctrtNo} || '%'
AND (A.APT_CMPLEX_NM LIKE '%' || #{aptNm} || '%' OR A.APT_CMPLEX_NO LIKE '%' || #{aptNm} || '%')
AND TRUNC(C.CTRT_APRV_DT) >= TO_DATE(#{aprvStartDt}, 'YYYY-MM-DD') AND TRUNC(C.CTRT_APRV_DT) <= TO_DATE(#{aprvEndDt}, 'YYYY-MM-DD') AND C.CTRT_STTS_CD = #{status}
AND (U2.USER_NM LIKE '%' || #{manager} || '%' OR U2.USER_ID LIKE '%' || #{manager} || '%' OR U2.USER_NO LIKE '%' || #{manager} || '%')
AND C.MVIN_DT >= TO_DATE(#{startDt}, 'YYYY-MM-DD') AND C.MVOUT_DT <= TO_DATE(#{endDt}, 'YYYY-MM-DD') AND (C.DPST_AMT >= TO_NUMBER(#{minRent}) OR C.MTHLY_RENT_AMT >= TO_NUMBER(#{minRent})) AND (C.DPST_AMT <= TO_NUMBER(#{maxRent}) OR C.MTHLY_RENT_AMT <= TO_NUMBER(#{maxRent}))
AND (U.USER_NM LIKE '%' || #{userSearch} || '%' OR U.USER_ID LIKE '%' || #{userSearch} || '%')
AND M.USER_NO = #{userNo}
ORDER BY C.RENT_CTRT_NO DESC ) B WHERE ROWNUM <= #{endRow} ) WHERE RNUM >= #{startRow}
